<template>
    <!-- 헤더 -->
    <main-header></main-header>

    <div id="snow-background"></div>

    <!-- 메인 -->
    <router-view v-slot="{ Component, route }">
        <Transition appear @before-enter="beforeEnter" @enter="enter" @afterEnger="afterEnter" :css="false">
            <main :key="route.name">
                <component :is="Component"></component>
            </main>
        </Transition>
    </router-view>

    <!-- 푸터 -->
    <main-footer></main-footer>
</template>

<script>
import gsap from 'gsap'
import particles from 'particles.js'
import MainHeader from '@/components/Main-Header.vue'
import MainFooter from '@/components/Main-Footer.vue'

export default {
    name: 'App',
    components: {
        MainHeader,
        MainFooter
    },
    data(){
        return{
            particlesJS: particles
        }
    },
    methods: {
        beforeEnter(el){
            gsap.set(el, { opacity: 0 });
        },
        enter(el, done){
            gsap.to(el, { opacity: 1, delay: 0.2, duration: 0.5, ease: "sine.out", onComplete: done });
        }
    },
    mounted(){
        window.scrollTo(0, 0);

        particlesJS('snow-background', {
            "particles": {
                "number": {
                    "value": 250,
                    "density": {
                        "enable": true,
                        "value_area": 800
                    }
                },
                "color": {
                    "value": "#fff"
                },
                "shape": {
                    "type": "circle",
                    "stroke": {
                        "width": 0,
                        "color": "#000000"
                    },
                    "polygon": {
                        "nb_sides": 5
                    },
                    "image": {
                        "src": "img/github.svg",
                        "width": 100,
                        "height": 100
                    }
                },
                "opacity": {
                    "value": 0.5,
                    "random": true,
                    "anim": {
                        "enable": false,
                        "speed": 1,
                        "opacity_min": 0.1,
                        "sync": false
                    }
                },
                "size": {
                    "value": 6,
                    "random": true,
                    "anim": {
                        "enable": false,
                        "speed": 40,
                        "size_min": 0.1,
                        "sync": false
                    }
                },
                "line_linked": {
                    "enable": false,
                    "distance": 500,
                    "color": "#ffffff",
                    "opacity": 0.4,
                    "width": 2
                },
                "move": {
                    "enable": true,
                    "speed": 1.5,
                    "direction": "bottom",
                    "random": false,
                    "straight": false,
                    "out_mode": "out",
                    "bounce": false,
                    "attract": {
                        "enable": false,
                        "rotateX": 600,
                        "rotateY": 1200
                    }
                }
            },
            "interactivity": {
                "detect_on": "canvas",
                "events": {
                    "onhover": {
                        "enable": false,
                        "mode": "bubble"
                    },
                    "onclick": {
                        "enable": false,
                        "mode": "repulse"
                    },
                    "resize": true
                },
                "modes": {
                    "grab": {
                        "distance": 400,
                        "line_linked": {
                            "opacity": 0.5
                        }
                    },
                    "bubble": {
                        "distance": 400,
                        "size": 4,
                        "duration": 0.3,
                        "opacity": 1,
                        "speed": 3
                    },
                    "repulse": {
                        "distance": 200,
                        "duration": 0.4
                    },
                    "push": {
                        "particles_nb": 4
                    },
                    "remove": {
                        "particles_nb": 2
                    }
                }
            },
            "retina_detect": true
        });
    }
}
</script>

<style lang="scss">
*{
    margin: 0;
    padding: 0;
    box-sizing: inherit;
}
html{
    overflow-x: hidden;
    font-family: $font_primary;
    font-size: 62.5%;
    color: $color_light;
    background-color: $color_dark;
    word-break: keep-all;
    overflow-wrap: break-word;
    box-sizing: border-box;
    user-select: none;
}
body{
    font-size: 1.6rem;
    line-height: 1.4;
}
main{
    overflow-x: hidden;
    position: relative;
    margin: auto;
    padding-top: 54px;
    max-width: 700px;
}
a{
    color: inherit;
    text-decoration: none;
}
ul{
    list-style: none;
}
button{
    background: transparent;
    cursor: pointer;
    border: none;
}
.blind{
    border: 0;
    clip: rect(0 0 0 0);
    clip-path: inset(50%);
    width: 1px;
    height: 1px;
    margin: -1px;
    overflow: hidden;
    padding: 0;
    position: absolute;
    white-space: nowrap;
}
#snow-background{
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    filter: blur(1px);
}
</style>